import asyncio
import json
import math
import signal
import time
import uuid
from dataclasses import dataclass, field, asdict
from typing import Dict, List, Optional, Tuple, Any

HOST = "0.0.0.0"
PORT = 8765
TICK_RATE = 20
WORLD_SIZE = 5000.0
PLAYER_RADIUS = 0.5
MAX_HEALTH = 100
MOVE_SPEED = 12.0
JUMP_VELOCITY = 8.0
GRAVITY = 24.0
BULLET_SPEED = 180.0
BULLET_LIFETIME = 2.0
FIRE_COOLDOWN = 0.1
RESPAWN_TIME = 5.0
MAX_NAME_LEN = 24
MAX_CLIENT_MSG_SIZE = 16 * 1024
BROADCAST_STATE = True

OBSTACLES = [
    {"x": 800.0, "y": 0.0, "z": 1200.0, "w": 200.0, "h": 200.0, "d": 200.0},
    {"x": 1800.0, "y": 0.0, "z": 2400.0, "w": 400.0, "h": 300.0, "d": 300.0},
    {"x": 3000.0, "y": 0.0, "z": 1000.0, "w": 300.0, "h": 250.0, "d": 300.0},
]

def now() -> float:
    return time.time()

def clamp(v: float, lo: float, hi: float) -> float:
    return lo if v < lo else hi if v > hi else v

def vec_len(x: float, y: float, z: float) -> float:
    return math.sqrt(x * x + y * y + z * z)

def normalize(x: float, y: float, z: float) -> Tuple[float, float, float]:
    l = vec_len(x, y, z)
    if l <= 1e-8:
        return 0.0, 0.0, 0.0
    return x / l, y / l, z / l

def distance_sq(a: Tuple[float, float, float], b: Tuple[float, float, float]) -> float:
    dx = a[0] - b[0]
    dy = a[1] - b[1]
    dz = a[2] - b[2]
    return dx * dx + dy * dy + dz * dz

def aabb_contains(x: float, y: float, z: float, box: Dict[str, float]) -> bool:
    return (
        box["x"] <= x <= box["x"] + box["w"] and
        box["y"] <= y <= box["y"] + box["h"] and
        box["z"] <= z <= box["z"] + box["d"]
    )

def line_intersects_aabb(p0: Tuple[float, float, float], p1: Tuple[float, float, float], box: Dict[str, float]) -> bool:
    tmin = 0.0
    tmax = 1.0
    for i, (start, end, bmin, bmax) in enumerate((
        (p0[0], p1[0], box["x"], box["x"] + box["w"]),
        (p0[1], p1[1], box["y"], box["y"] + box["h"]),
        (p0[2], p1[2], box["z"], box["z"] + box["d"]),
    )):
        d = end - start
        if abs(d) < 1e-8:
            if start < bmin or start > bmax:
                return False
        else:
            inv = 1.0 / d
            t1 = (bmin - start) * inv
            t2 = (bmax - start) * inv
            if t1 > t2:
                t1, t2 = t2, t1
            tmin = max(tmin, t1)
            tmax = min(tmax, t2)
            if tmin > tmax:
                return False
    return True

@dataclass
class PlayerInput:
    move_x: float = 0.0
    move_z: float = 0.0
    yaw: float = 0.0
    pitch: float = 0.0
    jump: bool = False
    fire: bool = False

@dataclass
class Player:
    id: str
    name: str
    writer: asyncio.StreamWriter
    x: float
    y: float
    z: float
    vx: float = 0.0
    vy: float = 0.0
    vz: float = 0.0
    yaw: float = 0.0
    pitch: float = 0.0
    health: int = MAX_HEALTH
    alive: bool = True
    score: int = 0
    input: PlayerInput = field(default_factory=PlayerInput)
    last_fire_time: float = 0.0
    respawn_at: float = 0.0

    def pos(self) -> Tuple[float, float, float]:
        return (self.x, self.y, self.z)

@dataclass
class Bullet:
    id: str
    owner_id: str
    x: float
    y: float
    z: float
    dx: float
    dy: float
    dz: float
    speed: float
    born: float

class BattleRoyaleServer:
    def __init__(self, host: str = HOST, port: int = PORT):
        self.host = host
        self.port = port
        self.server: Optional[asyncio.AbstractServer] = None
        self.players: Dict[str, Player] = {}
        self.bullets: Dict[str, Bullet] = {}
        self.running = True
        self.last_tick = now()

    def spawn_point(self) -> Tuple[float, float, float]:
        seed = time.time_ns() % 100000
        x = 100.0 + (seed % int(WORLD_SIZE - 200.0))
        z = 100.0 + ((seed // 7) % int(WORLD_SIZE - 200.0))
        return x, 0.0, z

    async def start(self):
        self.server = await asyncio.start_server(self.handle_client, self.host, self.port)
        loop = asyncio.get_running_loop()
        for sig in (signal.SIGINT, signal.SIGTERM):
            try:
                loop.add_signal_handler(sig, self.stop)
            except NotImplementedError:
                pass
        async with self.server:
            await asyncio.gather(self.server.serve_forever(), self.game_loop())

    def stop(self):
        self.running = False
        if self.server:
            self.server.close()

    async def handle_client(self, reader: asyncio.StreamReader, writer: asyncio.StreamWriter):
        player_id = str(uuid.uuid4())
        px, py, pz = self.spawn_point()
        player = Player(
            id=player_id,
            name=f"Player-{player_id[:8]}",
            writer=writer,
            x=px,
            y=py,
            z=pz,
        )
        self.players[player_id] = player
        await self.send(writer, {
            "type": "welcome",
            "id": player_id,
            "tick_rate": TICK_RATE,
            "world_size": WORLD_SIZE,
            "obstacles": OBSTACLES,
            "note": "Server broadcasts full game state. Clients are responsible for any local visibility or distance-based rendering decisions."
        })
        await self.broadcast({
            "type": "player_joined",
            "player": self.serialize_player(player)
        })

        try:
            while not reader.at_eof():
                raw = await reader.readline()
                if not raw:
                    break
                if len(raw) > MAX_CLIENT_MSG_SIZE:
                    break
                try:
                    msg = json.loads(raw.decode("utf-8"))
                except Exception:
                    continue
                await self.process_message(player_id, msg)
        except (ConnectionError, asyncio.IncompleteReadError):
            pass
        finally:
            await self.disconnect_player(player_id)

    async def process_message(self, player_id: str, msg: Dict[str, Any]):
        player = self.players.get(player_id)
        if not player:
            return
        mtype = msg.get("type")

        if mtype == "hello":
            name = str(msg.get("name", "")).strip()
            if name:
                player.name = name[:MAX_NAME_LEN]
        elif mtype == "input":
            inp = msg.get("input", {})
            player.input.move_x = clamp(float(inp.get("move_x", 0.0)), -1.0, 1.0)
            player.input.move_z = clamp(float(inp.get("move_z", 0.0)), -1.0, 1.0)
            player.input.yaw = float(inp.get("yaw", player.yaw))
            player.input.pitch = clamp(float(inp.get("pitch", player.pitch)), -89.0, 89.0)
            player.input.jump = bool(inp.get("jump", False))
            player.input.fire = bool(inp.get("fire", False))
        elif mtype == "ping":
            await self.send(player.writer, {"type": "pong", "t": msg.get("t", now())})

    async def disconnect_player(self, player_id: str):
        player = self.players.pop(player_id, None)
        if not player:
            return
        try:
            player.writer.close()
            await player.writer.wait_closed()
        except Exception:
            pass
        await self.broadcast({"type": "player_left", "id": player_id})

    async def send(self, writer: asyncio.StreamWriter, payload: Dict[str, Any]):
        try:
            writer.write((json.dumps(payload, separators=(",", ":")) + "\n").encode("utf-8"))
            await writer.drain()
        except Exception:
            pass

    async def broadcast(self, payload: Dict[str, Any]):
        data = (json.dumps(payload, separators=(",", ":")) + "\n").encode("utf-8")
        stale = []
        for pid, player in self.players.items():
            try:
                player.writer.write(data)
            except Exception:
                stale.append(pid)
        for pid in stale:
            await self.disconnect_player(pid)
        drains = []
        for player in self.players.values():
            drains.append(player.writer.drain())
        if drains:
            await asyncio.gather(*drains, return_exceptions=True)

    def serialize_player(self, p: Player) -> Dict[str, Any]:
        return {
            "id": p.id,
            "name": p.name,
            "x": round(p.x, 3),
            "y": round(p.y, 3),
            "z": round(p.z, 3),
            "vx": round(p.vx, 3),
            "vy": round(p.vy, 3),
            "vz": round(p.vz, 3),
            "yaw": round(p.yaw, 3),
            "pitch": round(p.pitch, 3),
            "health": p.health,
            "alive": p.alive,
            "score": p.score,
        }

    def serialize_bullet(self, b: Bullet) -> Dict[str, Any]:
        return {
            "id": b.id,
            "owner_id": b.owner_id,
            "x": round(b.x, 3),
            "y": round(b.y, 3),
            "z": round(b.z, 3),
            "dx": round(b.dx, 5),
            "dy": round(b.dy, 5),
            "dz": round(b.dz, 5),
            "speed": b.speed,
            "age": round(now() - b.born, 3),
        }

    def update_player(self, p: Player, dt: float):
        if not p.alive:
            if now() >= p.respawn_at:
                sx, sy, sz = self.spawn_point()
                p.x, p.y, p.z = sx, sy, sz
                p.vx = p.vy = p.vz = 0.0
                p.health = MAX_HEALTH
                p.alive = True
            return

        p.yaw = p.input.yaw
        p.pitch = p.input.pitch

        mx = p.input.move_x
        mz = p.input.move_z
        mag = math.sqrt(mx * mx + mz * mz)
        if mag > 1.0:
            mx /= mag
            mz /= mag

        yaw_rad = math.radians(p.yaw)
        forward_x = math.sin(yaw_rad)
        forward_z = math.cos(yaw_rad)
        right_x = math.cos(yaw_rad)
        right_z = -math.sin(yaw_rad)

        wish_x = forward_x * mz + right_x * mx
        wish_z = forward_z * mz + right_z * mx
        wish_x, _, wish_z = normalize(wish_x, 0.0, wish_z)

        p.vx = wish_x * MOVE_SPEED
        p.vz = wish_z * MOVE_SPEED

        on_ground = p.y <= 0.0001
        if on_ground:
            p.y = 0.0
            if p.vy < 0.0:
                p.vy = 0.0
            if p.input.jump:
                p.vy = JUMP_VELOCITY

        p.vy -= GRAVITY * dt

        nx = clamp(p.x + p.vx * dt, 0.0, WORLD_SIZE)
        ny = p.y + p.vy * dt
        nz = clamp(p.z + p.vz * dt, 0.0, WORLD_SIZE)

        collided = False
        for box in OBSTACLES:
            if aabb_contains(nx, max(0.0, ny), nz, box):
                collided = True
                break

        if not collided:
            p.x, p.y, p.z = nx, max(0.0, ny), nz
        else:
            p.vx = p.vz = 0.0

        if p.y <= 0.0:
            p.y = 0.0
            if p.vy < 0.0:
                p.vy = 0.0

        if p.input.fire and (now() - p.last_fire_time) >= FIRE_COOLDOWN:
            self.fire_bullet(p)
            p.last_fire_time = now()

    def fire_bullet(self, p: Player):
        if not p.alive:
            return
        yaw = math.radians(p.yaw)
        pitch = math.radians(p.pitch)
        dx = math.sin(yaw) * math.cos(pitch)
        dy = -math.sin(pitch)
        dz = math.cos(yaw) * math.cos(pitch)
        dx, dy, dz = normalize(dx, dy, dz)
        bullet = Bullet(
            id=str(uuid.uuid4()),
            owner_id=p.id,
            x=p.x,
            y=p.y + 1.6,
            z=p.z,
            dx=dx,
            dy=dy,
            dz=dz,
            speed=BULLET_SPEED,
            born=now(),
        )
        self.bullets[bullet.id] = bullet

    def update_bullets(self, dt: float):
        expired = []
        for bid, b in self.bullets.items():
            if now() - b.born > BULLET_LIFETIME:
                expired.append(bid)
                continue

            ox, oy, oz = b.x, b.y, b.z
            b.x += b.dx * b.speed * dt
            b.y += b.dy * b.speed * dt
            b.z += b.dz * b.speed * dt

            if not (0.0 <= b.x <= WORLD_SIZE and 0.0 <= b.z <= WORLD_SIZE and 0.0 <= b.y <= 500.0):
                expired.append(bid)
                continue

            hit_obstacle = False
            for box in OBSTACLES:
                if line_intersects_aabb((ox, oy, oz), (b.x, b.y, b.z), box):
                    hit_obstacle = True
                    break
            if hit_obstacle:
                expired.append(bid)
                continue

            for pid, p in self.players.items():
                if pid == b.owner_id or not p.alive:
                    continue
                if distance_sq((b.x, b.y, b.z), (p.x, p.y + 1.0, p.z)) <= (PLAYER_RADIUS + 0.25) ** 2:
                    p.health -= 25
                    if p.health <= 0:
                        p.health = 0
                        p.alive = False
                        p.respawn_at = now() + RESPAWN_TIME
                        owner = self.players.get(b.owner_id)
                        if owner:
                            owner.score += 1
                    expired.append(bid)
                    break

        for bid in expired:
            self.bullets.pop(bid, None)

    async def game_loop(self):
        tick_dt = 1.0 / TICK_RATE
        while self.running:
            start = now()
            dt = min(start - self.last_tick, 0.1)
            self.last_tick = start

            for p in list(self.players.values()):
                self.update_player(p, dt)

            self.update_bullets(dt)

            if BROADCAST_STATE:
                state = {
                    "type": "state",
                    "server_time": round(now(), 3),
                    "players": [self.serialize_player(p) for p in self.players.values()],
                    "bullets": [self.serialize_bullet(b) for b in self.bullets.values()],
                    "obstacles": OBSTACLES,
                }
                await self.broadcast(state)

            elapsed = now() - start
            await asyncio.sleep(max(0.0, tick_dt - elapsed))

async def main():
    server = BattleRoyaleServer()
    try:
        await server.start()
    except asyncio.CancelledError:
        pass

if __name__ == "__main__":
    asyncio.run(main())